readonly KEYCHAIN_ACCOUNT="upload"
readonly ORIGIN="${LEENK_STATIC_ORIGIN:-https://www.yusoofsh.id}"
readonly REPO="${LEENK_REPO:-$HOME/Developer/Community/leenk}"

usage() {
  cat <<'EOF'
Upload files to https://www.yusoofsh.id/static/.

Usage:
  leenk-static.sh auth
  leenk-static.sh upload FILE [REMOTE_PATH]
  leenk-static.sh head REMOTE_PATH
  leenk-static.sh delete [--force] REMOTE_PATH
  leenk-static.sh --help
  leenk-static.sh --version

Commands:
  auth    Generate a token, save it in macOS Keychain, and rotate the Worker secret.
  upload  POST FILE as binary data. REMOTE_PATH defaults to FILE's basename.
  head    Check a public file and show its HTTP response headers.
  delete  Permanently delete a file after confirmation. Use --force for automation.

Examples:
  leenk-static.sh auth
  leenk-static.sh upload ./document.pdf
  leenk-static.sh upload ./image.png images/avatar.png
  leenk-static.sh head images/avatar.png
  leenk-static.sh delete images/avatar.png

Environment:
  LEENK_REPO           Worker repository (default: ~/Developer/Community/leenk)
  LEENK_STATIC_ORIGIN  Public origin (default: https://www.yusoofsh.id)
EOF
}

die() {
  printf 'Error: %s\n' "$*" >&2
  exit 1
}

require_command() {
  command -v "$1" >/dev/null 2>&1 || die "required command not found: $1"
}

validate_remote_path() {
  local path="$1" segment

  [[ -n "$path" ]] || die "remote path cannot be empty"
  [[ "$path" != /* ]] || die "remote path must not start with /"
  [[ "$path" != */ ]] || die "remote path must name a file"

  IFS='/' read -r -a segments <<< "$path"
  for segment in "${segments[@]}"; do
    [[ -n "$segment" && "$segment" != "." && "$segment" != ".." ]] ||
      die "remote path contains an invalid segment"
  done
}

encoded_remote_path() {
  jq -rn --arg path "$1" '$path | split("/") | map(@uri) | join("/")'
}

public_url() {
  printf '%s/static/%s' "${ORIGIN%/}" "$(encoded_remote_path "$1")"
}

keychain_token() {
  security find-generic-password \
    -s "$KEYCHAIN_SERVICE" \
    -a "$KEYCHAIN_ACCOUNT" \
    -w 2>/dev/null ||
    die "upload token is not configured; run: $0 auth"
}

store_keychain_token() {
  local token="$1"

  printf '%s\n' "$token" | \
    LEENK_KEYCHAIN_SERVICE="$KEYCHAIN_SERVICE" \
    LEENK_KEYCHAIN_ACCOUNT="$KEYCHAIN_ACCOUNT" \
    expect -c '
    log_user 0
    set timeout 10
    if {[gets stdin password] < 0} { exit 2 }
    set service $env(LEENK_KEYCHAIN_SERVICE)
    set account $env(LEENK_KEYCHAIN_ACCOUNT)
    spawn /usr/bin/security add-generic-password -U -s $service -a $account -w
    expect {
      -re {password data for new item:|password data for item:} {
        send -- "$password\r"
      }
      timeout { exit 3 }
      eof { exit 4 }
    }
    expect {
      -re {retype password for new item:} {
        send -- "$password\r"
        expect eof
      }
      eof {}
      timeout { exit 5 }
    }
    set result [wait]
    exit [lindex $result 3]
  '
}

wait_for_credential() {
  local token="$1" attempt status

  printf 'Waiting for the new credential to reach the edge' >&2
  for attempt in {1..15}; do
    status=$(printf 'header = "Authorization: Bearer %s"\n' "$token" | curl \
      --config - \
      --silent \
      --show-error \
      --connect-timeout 5 \
      --max-time 10 \
      --request POST \
      --header 'Content-Type: application/octet-stream' \
      --header 'Content-Length: 0' \
      --output /dev/null \
      --write-out '%{http_code}' \
      "${ORIGIN%/}/static/.auth-check" 2>/dev/null) || status=000

    if [[ "$status" == "400" ]]; then
      printf ' ready.\n' >&2
      return 0
    fi
    if [[ "$status" != "401" && "$status" != "000" ]]; then
      printf '\n' >&2
      die "credential readiness check returned HTTP $status"
    fi

    printf '.' >&2
    sleep 2
  done

  printf '\n' >&2
  die "credential update was submitted but did not reach the edge within 30 seconds; retry the upload shortly"
}

authenticate() {
  local new_token old_token="" had_old=0

  require_command openssl
  require_command security
  require_command expect
  require_command curl
  [[ -f "$REPO/wrangler.jsonc" ]] || die "Worker project not found at $REPO"

  if old_token=$(security find-generic-password -s "$KEYCHAIN_SERVICE" -a "$KEYCHAIN_ACCOUNT" -w 2>/dev/null); then
    had_old=1
  fi

  new_token=$(openssl rand -hex 32)
  store_keychain_token "$new_token"

  printf 'Rotating the production upload credential...\n' >&2
  if ! printf '%s' "$new_token" | (cd "$REPO" && nub exec wrangler secret put STATIC_UPLOAD_TOKEN); then
    if [[ "$had_old" -eq 1 ]]; then
      store_keychain_token "$old_token"
    else
      security delete-generic-password \
        -s "$KEYCHAIN_SERVICE" \
        -a "$KEYCHAIN_ACCOUNT" >/dev/null 2>&1 || true
    fi
    die "Worker secret update failed; Keychain was restored"
  fi

  wait_for_credential "$new_token"
  printf 'Authentication configured in macOS Keychain.\n'
}

upload() {
  local file_path="$1" remote_path="${2:-}" token url content_type response

  require_command curl
  require_command file
  require_command jq
  require_command security

  [[ -f "$file_path" ]] || die "file not found: $file_path"
  [[ -r "$file_path" ]] || die "file is not readable: $file_path"
  [[ -n "$remote_path" ]] || remote_path=$(basename "$file_path")
  validate_remote_path "$remote_path"

  token=$(keychain_token)
  url=$(public_url "$remote_path")
  content_type=$(file --brief --mime-type "$file_path")

  printf 'Uploading %s to %s...\n' "$file_path" "$url" >&2
  response=$(printf 'header = "Authorization: Bearer %s"\n' "$token" | curl \
    --config - \
    --silent \
    --show-error \
    --fail-with-body \
    --connect-timeout 10 \
    --max-time 300 \
    --request POST \
    --header "Content-Type: $content_type" \
    --data-binary "@$file_path" \
    "$url") || die "upload failed"

  if ! jq -e '.url and .path and (.size | type == "number")' >/dev/null 2>&1 <<< "$response"; then
    printf '%s\n' "$response" >&2
    die "server did not confirm the upload"
  fi

  printf '%s\n' "$url"
}

head_object() {
  local remote_path="$1"

  require_command curl
  require_command jq
  validate_remote_path "$remote_path"
  curl \
    --silent \
    --show-error \
    --fail \
    --connect-timeout 10 \
    --max-time 30 \
    --head \
    "$(public_url "$remote_path")"
}

delete_object() {
  local remote_path="$1" force="$2" token url answer http_code

  require_command curl
  require_command jq
  require_command security
  validate_remote_path "$remote_path"
  url=$(public_url "$remote_path")

  if [[ "$force" -ne 1 ]]; then
    [[ -t 0 ]] || die "confirmation requires a terminal; rerun with --force"
    printf 'Permanently delete %s? [y/N] ' "$url" >&2
    IFS= read -r answer
    case "$answer" in
      y|Y|yes|YES|Yes) ;;
      *) die "delete cancelled" ;;
    esac
  fi

  token=$(keychain_token)
  printf 'Deleting %s...\n' "$url" >&2
  if ! http_code=$(printf 'header = "Authorization: Bearer %s"\n' "$token" | curl \
    --config - \
    --silent \
    --show-error \
    --connect-timeout 10 \
    --max-time 30 \
    --request DELETE \
    --header 'Content-Type: application/octet-stream' \
    --output /dev/null \
    --write-out '%{http_code}' \
    "$url"); then
    die "delete failed"
  fi

  [[ "$http_code" == "204" ]] || die "delete failed with HTTP $http_code"
  printf '%s\n' "$url"
}

case "${1:-}" in
  auth)
    [[ "$#" -eq 1 ]] || die "auth takes no arguments"
    authenticate
    ;;
  upload)
    [[ "$#" -ge 2 && "$#" -le 3 ]] || die "usage: $0 upload FILE [REMOTE_PATH]"
    upload "$2" "${3:-}"
    ;;
  head)
    [[ "$#" -eq 2 ]] || die "usage: $0 head REMOTE_PATH"
    head_object "$2"
    ;;
  delete)
    shift
    force=0
    remote_path=""
    while [[ "$#" -gt 0 ]]; do
      case "$1" in
        --force)
          force=1
          ;;
        -*)
          die "unknown delete option: $1"
          ;;
        *)
          [[ -z "$remote_path" ]] || die "delete accepts one remote path"
          remote_path="$1"
          ;;
      esac
      shift
    done
    [[ -n "$remote_path" ]] || die "usage: $0 delete [--force] REMOTE_PATH"
    delete_object "$remote_path" "$force"
    ;;
  -h|--help|help)
    usage
    ;;
  --version)
    printf 'leenk-static.sh %s\n' "$VERSION"
    ;;
  '')
    usage >&2
    exit 2
    ;;
  *)
    die "unknown command: $1 (use --help)"
    ;;

    });
  }

  return null;
}

function serveObject(
  object: StaticFileObject | null,
  headOnly: boolean,
): Response {
  if (!object) return apiError(404, "NOT_FOUND", "Static file not found");

  const headers = new Headers({
    "Cache-Control": object.metadata.cacheControl,
    "Content-Length": String(object.size),
    "Content-Type": object.metadata.contentType,
    ETag: object.httpEtag,
    "Last-Modified": object.uploaded.toUTCString(),
    "X-Content-Type-Options": "nosniff",
  });
  setOptionalHeader(
    headers,
    "Content-Disposition",
    object.metadata.contentDisposition,
  );
  setOptionalHeader(
    headers,
    "Content-Encoding",
    object.metadata.contentEncoding,
  );
  setOptionalHeader(
    headers,
    "Content-Language",
    object.metadata.contentLanguage,
  );

  return new Response(headOnly ? null : object.body, { headers });
}

function requestMetadata(headers: Headers): StaticFileMetadata {
  const metadata: StaticFileMetadata = {
    cacheControl: headers.get("cache-control") ?? DEFAULT_CACHE_CONTROL,
    contentType: headers.get("content-type") ?? "application/octet-stream",
  };
  copyHeader(headers, "content-disposition", metadata, "contentDisposition");
  copyHeader(headers, "content-encoding", metadata, "contentEncoding");
  copyHeader(headers, "content-language", metadata, "contentLanguage");
  return metadata;
}

function validateObjectKey(key: string): string | null {
  if (key.length > MAX_OBJECT_KEY_LENGTH) return "The file path is too long";
  if (key.includes("\\") || key.includes("\0"))
    return "The file path is invalid";

  const segments = key.split("/");
  if (
    segments.some((segment) => !segment || segment === "." || segment === "..")
  ) {
    return "The file path is invalid";
  }

  return null;
}

function parseContentLength(value: string | null): number | null {
  if (value === null) return null;
  if (!/^\d+$/.test(value)) throw new UploadTooLargeError();

  const parsed = Number(value);
  if (!Number.isSafeInteger(parsed)) throw new UploadTooLargeError();
  return parsed;
}

async function tokensMatch(
  provided: string,
  expected: string,
): Promise<boolean> {
  const encoder = new TextEncoder();
  const [providedHash, expectedHash] = await Promise.all([
    crypto.subtle.digest("SHA-256", encoder.encode(provided)),
    crypto.subtle.digest("SHA-256", encoder.encode(expected)),
  ]);
  const subtle = crypto.subtle as SubtleCrypto & {
    timingSafeEqual?: (a: ArrayBuffer, b: ArrayBuffer) => boolean;
  };
  if (subtle.timingSafeEqual)
    return subtle.timingSafeEqual(providedHash, expectedHash);

  const a = new Uint8Array(providedHash);
  const b = new Uint8Array(expectedHash);
  let mismatch = 0;
  for (let index = 0; index < a.length; index += 1)
    mismatch |= a[index]! ^ b[index]!;
  return mismatch === 0;
}

function copyHeader(
  headers: Headers,
  headerName: string,
  metadata: StaticFileMetadata,
  metadataName: "contentDisposition" | "contentEncoding" | "contentLanguage",
): void {
  const value = headers.get(headerName);
  if (value) metadata[metadataName] = value;
}

function setOptionalHeader(
  headers: Headers,
  name: string,
  value: string | undefined,
): void {
  if (value) headers.set(name, value);
}

function apiError(
  status: number,
  code: string,
  message: string,
  headers?: HeadersInit,
): Response {
  const responseHeaders = new Headers(headers);
  responseHeaders.set("Cache-Control", "no-store");
  return Response.json(
    { error: { code, message } },
    {
      status,
      headers: responseHeaders,
    },
  );
}
