export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    if (url.pathname === "/backfill") {
      if (
        request.method !== "POST" ||
        request.headers.get("x-confirm-backfill") !== "uploaded-plus-14d"
      ) {
        return Response.json(
          { error: "Explicit uploaded-plus-14d confirmation required" },
          { status: 412 },
        );
      }

      const candidates = await listObjects(env.STATIC_BUCKET);
      const results = [];
      for (const candidate of candidates) {
        if (candidate.customMetadata?.expiresAt) {
          results.push({ key: candidate.key, status: "already_set" });
          continue;
        }

        const source = await env.STATIC_BUCKET.get(candidate.key, {
          onlyIf: { etagMatches: candidate.etag },
        });
        if (!source?.body) {
          results.push({ key: candidate.key, status: "conflict_before_read" });
          continue;
        }

        const expiresAt = new Date(
          source.uploaded.getTime() + 14 * 24 * 60 * 60 * 1000,
        ).toISOString();
        const body = await source.arrayBuffer();
        const written = await env.STATIC_BUCKET.put(candidate.key, body, {
          onlyIf: { etagMatches: source.etag },
          httpMetadata: source.httpMetadata,
          customMetadata: { ...source.customMetadata, expiresAt },
          storageClass: source.storageClass,
          md5: source.checksums.md5,
        });
        if (!written) {
          results.push({ key: candidate.key, status: "conflict_before_write" });
          continue;
        }

        const verified = await env.STATIC_BUCKET.head(candidate.key);
        results.push({
          key: candidate.key,
          status:
            verified?.customMetadata?.expiresAt === expiresAt
              ? "backfilled"
              : "verification_failed",
          expiresAt,
          contentUnchanged: written.etag === source.etag,
        });
      }

      return Response.json({ count: results.length, results });
    }

    if (url.pathname !== "/inventory" || request.method !== "GET") {
      return new Response("Not found", { status: 404 });
    }

    const listed = await listObjects(env.STATIC_BUCKET);
    const objects = listed.map((object) => ({
      key: object.key,
      size: object.size,
      uploaded: object.uploaded.toISOString(),
      etag: object.httpEtag,
      customMetadata: object.customMetadata,
      httpMetadata: object.httpMetadata,
    }));

    return Response.json({ count: objects.length, objects });
  },
};

async function listObjects(bucket) {
    const objects = [];
    let cursor;
    do {
      const page = await bucket.list({
        cursor,
        include: ["customMetadata", "httpMetadata"],
      });
      objects.push(...page.objects);
      cursor = page.truncated ? page.cursor : undefined;
    } while (cursor);

    return objects;
}
